WITH ed AS (SELECT user_id, artist_name FROM public.artist_requests WHERE lower(artist_name) = 'ed martin' AND status = 'approved' LIMIT 1) UPDATE public.song_collaborators sc SET claimed_by_user_id = NULL, claimed_at = NULL FROM ed WHERE sc.claimed_by_user_id = ed.user_id AND lower(sc.artist_name) = lower(ed.artist_name);
WITH ed AS (SELECT user_id, artist_name FROM public.artist_requests WHERE lower(artist_name) = 'ed martin' AND status = 'approved' LIMIT 1) INSERT INTO public.collaboration_claims (collaborator_id, claimant_user_id, claimant_artist_name, status, message) SELECT sc.id, ed.user_id, ed.artist_name, 'pending', 'Reclamacion regenerada al cambiar el flujo: requiere revision administrativa.' FROM public.song_collaborators sc, ed WHERE sc.song_id IS NOT NULL AND sc.claimed_by_user_id IS NULL AND lower(sc.artist_name) = lower(ed.artist_name) AND NOT EXISTS (SELECT 1 FROM public.collaboration_claims cc WHERE cc.collaborator_id = sc.id AND cc.claimant_user_id = ed.user_id AND cc.status = 'pending');
WITH ed AS (SELECT user_id, artist_name FROM public.artist_requests WHERE lower(artist_name) = 'ed martin' AND status = 'approved' LIMIT 1), counts AS (SELECT ed.user_id u, ed.artist_name n, (SELECT COUNT(*) FROM public.collaboration_claims WHERE claimant_user_id = ed.user_id AND status = 'pending') c FROM ed) INSERT INTO public.notifications (user_id, type, title, body, data) SELECT u, 'collab_auto_assigned', 'Hemos detectado colaboraciones a tu nombre', 'Encontramos ' || c || ' colaboracion(es) en el catalogo a nombre de ' || n || '. Revisalas en tu panel de artista en Colaboraciones.', jsonb_build_object('artist_name', n, 'count', c) FROM counts WHERE c > 0;
WITH ed AS (SELECT user_id, artist_name FROM public.artist_requests WHERE lower(artist_name) = 'ed martin' AND status = 'approved' LIMIT 1), counts AS (SELECT ed.user_id u, ed.artist_name n, (SELECT COUNT(*) FROM public.collaboration_claims WHERE claimant_user_id = ed.user_id AND status = 'pending') c FROM ed) INSERT INTO public.notifications (user_id, type, title, body, data) SELECT u, 'collab_claim_pending', 'Reclamacion pendiente de revision', 'Tienes ' || c || ' reclamacion(es) en revision por el equipo. Te avisaremos cuando se aprueben. Hasta entonces, las regalias permanecen retenidas en el pozo.', jsonb_build_object('artist_name', n, 'count', c) FROM counts WHERE c > 0;